def gen(rng, size):
    n = max(1, size)
    out = []
    depth = 0
    expect_value = True
    count = 0
    while count < n:
        if expect_value:
            r = rng.random()
            if r < 0.2 and depth < 8:
                out.append('('); depth += 1
            elif r < 0.35:
                out.append('-')
                out.append(str(rng.randint(0, 999)))
                expect_value = False; count += 1
            else:
                out.append(str(rng.randint(0, 999)))
                expect_value = False; count += 1
        else:
            if depth > 0 and rng.random() < 0.3:
                out.append(')'); depth -= 1
            else:
                out.append(rng.choice(['+', '-']))
                expect_value = True
        if rng.random() < 0.2:
            out.append(' ')
    while not expect_value and depth > 0 and rng.random() < 0.8:
        out.append(')'); depth -= 1
    if expect_value:
        out.append(str(rng.randint(0, 999)))
    while depth > 0:
        out.append(')'); depth -= 1
    return [''.join(out)]

