class Solution:
    def calculate(self, s):
        tokens = []
        i = 0
        while i < len(s):
            c = s[i]
            if c == ' ':
                i += 1
            elif c.isdigit():
                j = i
                while j < len(s) and s[j].isdigit():
                    j += 1
                tokens.append(int(s[i:j]))
                i = j
            else:
                tokens.append(c)
                i += 1
        pos = [0]
        def parse_expr():
            val = parse_term()
            while pos[0] < len(tokens) and tokens[pos[0]] in ('+', '-'):
                op = tokens[pos[0]]; pos[0] += 1
                rhs = parse_term()
                val = val + rhs if op == '+' else val - rhs
            return val
        def parse_term():
            if tokens[pos[0]] == '-':
                pos[0] += 1
                return -parse_term()
            if tokens[pos[0]] == '(':
                pos[0] += 1
                v = parse_expr()
                pos[0] += 1
                return v
            v = tokens[pos[0]]; pos[0] += 1
            return v
        return parse_expr()

