var calculate = function(s) {
    let total = 0, sign = 1, num = 0;
    const stack = [];
    for (const c of s) {
        if (c >= '0' && c <= '9') {
            num = num * 10 + (c.charCodeAt(0) - 48);
        } else if (c === '+') {
            total += sign * num; num = 0; sign = 1;
        } else if (c === '-') {
            total += sign * num; num = 0; sign = -1;
        } else if (c === '(') {
            stack.push(total); stack.push(sign);
            total = 0; sign = 1; num = 0;
        } else if (c === ')') {
            total += sign * num; num = 0;
            const prevSign = stack.pop();
            const prevTotal = stack.pop();
            total = prevTotal + prevSign * total;
            sign = 1;
        }
    }
    total += sign * num;
    return total;
};
